/Parsers/System/Gigamon/GigamonTI.parser_text:
[parser]
FORMAT=JSON

MAPPER:vendor = Gigamon
MAPPER:Product = ThreatInsight
MAPPER:event_id = {{event_type}}

START_TIME_FIELD = timestamp
TIME_PARSER = yyyy-MM-dd'T'HH:mm:ss.SSSX

SET:{{indicators.1.field}} = {{indicators.1.values.1}}
SET:{{indicators.2.field}} = {{indicators.2.values.1}}
SET:{{indicators.3.field}} = {{indicators.3.values.1}}
SET:{{indicators.4.field}} = {{indicators.4.values.1}}

/Parsers/System/Honeywell/Honeywell Pro-.parser_text:
[parser]
FORMAT = CEF

#Handle the product info
MAPPER:vendor = Honeywell
MAPPER:product = Pro Watch
MAPPER:event_id = {{name}}

#Handle time
START_TIME_FIELD = _messagetime
TIME_PARSER = X1000

FIND_REPLACE:categoryOutcome: = ^/

SET:{{cn1Label}} = {{cn1}}
SET:{{cs1Label}} = {{cs1}}
SET:{{cs2Label}} = {{cs2}}
SET:{{cs3Label}} = {{cs3}}
SET:{{cs4Label}} = {{cs4}}
SET:{{cs5Label}} = {{cs5}}
SET:{{cs6Label}} = {{cs6}}
SET:{{flexString1Label}} = {{flexString1}}
SET:{{flexString2Label}} = {{flexString2}}
SET:{{deviceCustomDate1Label}} = {{deviceCustomDate1}}
SET:{{deviceCustomDate2Label}} = {{deviceCustomDate2}}
SET:{{flexNumber1Label}} = {{flexNumber1}}
SET:{{flexNumber2}} = {{flexNumber2}}

# Drop unneccessary fields
DROP:r|.*Label$ = true
DROP:r|.*\d = true

